/**
 * Representation of an [SD-JWT](https://www.rfc-editor.org/rfc/rfc9901.html#name-sd-jwt-and-sd-jwtkb-data-fo)
 * of the format `<Issuer-signed JWT>~<D.1>~<D.2>~...~<D.N>~<optional KB-JWT>`.
 */
export class SdJwt {
    private constructor();
    free(): void;
    [Symbol.dispose](): void;
    /**
     * Attaches a {@link KeyBindingJwt} to this {@link SdJwt} token.
     * ## Notes
     * This method does *not* validate the given {@link KeyBindingJwt} in any way.
     */
    attachKeyBindingJwt(kb_jwt: KeyBindingJwt): void;
    /**
     * Returns the raw SD-JWT claims object.
     */
    claims(): SdJwtClaims;
    /**
     * Returns a list of disclosure strings.
     */
    disclosures(): string[];
    /**
     * Returns the JWT headers of this SD-JWT token.
     */
    headers(): object;
    /**
     * Returns the JSON object obtained by replacing all disclosures into their
     * corresponding JWT concealable claims.
     */
    intoDisclosedObject(): any;
    /**
     * Attempts to parse a semantically valid {@link SdJwt} from the given string.
     */
    static parse(s: string): SdJwt;
    /**
     * Returns the string representation for this SD-JWT token.
     */
    presentation(): string;
    /**
     * Returns the issuer's key binding requirements for this token, if any.
     */
    requiredKeyBind(): RequiredKeyBinding | undefined;
    toJSON(): any;
    toString(): any;
}

/**
 * A class for constructing an {@link SdJwt} in a step-by-step manner.
 */
export class SdJwtBuilder {
    free(): void;
    [Symbol.dispose](): void;
    /**
     * Adds a decoy digest to the specified path.
     *
     * `path` indicates the pointer to the value that will be concealed using the syntax of
     * [JSON pointer](https://datatracker.ietf.org/doc/html/rfc6901).
     *
     * Use `path` = "" to add decoys to the top level.
     */
    addDecoys(path: string, number_of_decoys: number): SdJwtBuilder;
    /**
     * Creates an {@link SdJwtVc} with the provided data.
     */
    finish(signer: JwsSigner, alg: string): Promise<SdJwt>;
    /**
     * Sets a single JWT header by its key and value.
     */
    header(key: string, value: any): SdJwtBuilder;
    /**
     * Sets the JWT header.
     * ## Notes
     * - if {@link SdJwtVcBuilder.header} is not called, the default header is used: ```json { "typ": "sd-jwt", "alg":
     *   "<algorithm used in SdJwtBuilder.finish>" } ```
     * - `alg` is always replaced with the value passed to {@link SdJwtVcBuilder.finish}.
     */
    headers(headers: object): SdJwtBuilder;
    /**
     * Adds a new claim to the underlying object.
     */
    insertClaim(key: string, value: any): SdJwtBuilder;
    /**
     * Substitutes a value with the digest of its disclosure.
     *
     * ## Notes
     * - `path` indicates the pointer to the value that will be concealed using the syntax of [JSON pointer](https://datatracker.ietf.org/doc/html/rfc6901).
     */
    makeConcealable(path: string): SdJwtBuilder;
    /**
     * Creates a new {@link SdJwtVcBuilder} using `object` JSON representation and a given
     * hasher `hasher`.
     */
    constructor(object: object, hasher: Hasher, salt_size?: number | null);
    /**
     * Require a proof of possession of a given key from the holder.
     *
     * This operation adds a JWT confirmation (`cnf`) claim as specified in
     * [RFC8300](https://www.rfc-editor.org/rfc/rfc7800.html#section-3).
     */
    requireKeyBinding(key_bind: RequiredKeyBinding): SdJwtBuilder;
}

/**
 * A type for decoding and validating SD-JWT credentials.
 */
export class SdJwtCredentialValidator {
    free(): void;
    [Symbol.dispose](): void;
    /**
     * Creates a new `SdJwtCredentialValidator`. If a `signatureVerifier` is provided it will be used when
     * verifying decoded JWS signatures, otherwise a default verifier capable of handling the `EdDSA`, `ES256`, `ES256K`
     * algorithms will be used.
     */
    constructor(hasher: Hasher, signatureVerifier?: IJwsVerifier | null);
    /**
     * Decodes and validates a [Credential] issued as an SD-JWT.
     * The credential is constructed by replacing disclosures following the
     * [Selective Disclosure for JWTs (SD-JWT)](https://www.rfc-editor.org/rfc/rfc9901.html) standard.
     *
     * The following properties are validated according to `options`:
     * - the issuer's signature on the JWS,
     * - the expiration date,
     * - the issuance date,
     * - the semantic structure.
     *
     * # Warning
     * * The key binding JWT is not validated. If needed, it must be validated separately using {@link
     *   SdJwtCredentialValidator.validateKeyBindingJwt}.
     * * The lack of an error returned from this method is in of itself not enough to conclude that the credential can be
     *   trusted. This section contains more information on additional checks that should be carried out before and after
     *   calling this method.
     *
     * ## The state of the issuer's DID Document
     * The caller must ensure that `issuer` represents an up-to-date DID Document.
     *
     * ## Properties that are not validated
     *  There are many properties defined in [The Verifiable Credentials Data Model](https://www.w3.org/TR/vc-data-model/) that are **not** validated, such as:
     * `proof`, `credentialStatus`, `type`, `credentialSchema`, `refreshService` **and more**.
     * These should be manually checked after validation, according to your requirements.
     *
     * # Errors
     * An error is returned whenever a validated condition is not satisfied.
     */
    validateCredential(sd_jwt: SdJwt, issuer: CoreDocument | IToCoreDocument, options: JwtCredentialValidationOptions): Credential;
    /**
     * Decodes and validates a {@link CredentialV2} issued as an SD-JWT.
     * The credential is constructed by replacing disclosures following the
     * [Selective Disclosure for JWTs (SD-JWT)](https://www.rfc-editor.org/rfc/rfc9901.html) standard.
     *
     * The following properties are validated according to `options`:
     * - the issuer's signature on the JWS,
     * - the expiration date,
     * - the issuance date,
     * - the semantic structure.
     *
     * # Warning
     * * The key binding JWT is not validated. If needed, it must be validated separately using {@link
     *   SdJwtCredentialValidator.validate_key_binding_jwt}.
     * * The lack of an error returned from this method is in of itself not enough to conclude that the credential can be
     *   trusted. This section contains more information on additional checks that should be carried out before and after
     *   calling this method.
     *
     * ## The state of the issuer's DID Document
     * The caller must ensure that `issuer` represents an up-to-date DID Document.
     *
     * ## Properties that are not validated
     * There are many properties defined in [The Verifiable Credentials Data Model v2.0](https://www.w3.org/TR/vc-data-model-2.0/)
     * that are **not** validated, such as:
     * `proof`, `credentialStatus`, `type`, `credentialSchema`, `refreshService` **and more**.
     * These should be manually checked after validation, according to your requirements.
     *
     * # Errors
     * An error is returned whenever a validated condition is not satisfied.
     */
    validateCredentialV2(sd_jwt: SdJwt, issuer: CoreDocument | IToCoreDocument, options: JwtCredentialValidationOptions): CredentialV2;
    /**
     * Validates a [Key Binding JWT (KB-JWT)](https://www.rfc-editor.org/rfc/rfc9901.html#name-key-binding-jwt)
     * according to [RFC9901](https://www.rfc-editor.org/rfc/rfc9901.html#key_binding_security).
     *
     * The Validation process includes:
     *   - Signature validation using public key materials defined in the `holder` document.
     *   - `sd_hash` claim value in the KB-JWT claim.
     *   - Optional `nonce`, `aud`, and validity period validation.
     *
     * ## Notes
     * If a KB-JWT is not required by the SD-JWT, this method returns successfully early.
     */
    validateKeyBindingJwt(sd_jwt: SdJwt, holder: CoreDocument | IToCoreDocument, options: KeyBindingJwtValidationOptions): void;
    /**
     * Decode and verify the JWS signature of an SD-JWT using the DID Document of a trusted issuer.
     *
     * # Warning
     * The caller must ensure that the DID Documents of the trusted issuers are up-to-date.
     *
     * # Errors
     * An error is returned whenever:
     * - The JWS signature is invalid;
     * - The issuer's public key could not be determined or is not found within the trusted issuers' documents;
     */
    verifySignature(credential: SdJwt, trustedIssuers: Array<CoreDocument | IToCoreDocument>, options: JwsVerificationOptions): void;
}

/**
 * A class that enables users to conceal or disclose disclosable claims
 * within an {@link SdJwt}.
 */
export class SdJwtPresentationBuilder {
    free(): void;
    [Symbol.dispose](): void;
    /**
     * Removes the disclosure for the property at `path`, concealing it.
     *
     * ## Notes
     * - When concealing a claim more than one disclosure may be removed: the disclosure for the claim itself and the
     *   disclosures for any concealable sub-claim.
     */
    conceal(path: string): SdJwtPresentationBuilder;
    /**
     * Removes all disclosures from this SD-JWT, resulting in a token that,
     * when presented, will have *all* selectively-disclosable properties
     * omitted.
     */
    conceal_all(): SdJwtPresentationBuilder;
    /**
     * Discloses a value that was previously concealed.
     * # Notes
     * - This method may disclose multiple values, if the given path references a disclosable value stored within another
     *   disclosable value. That is, {@link SdJwtPresentationBuilder.disclose} will unconceal the selectively disclosable
     *   value at `path` together with *all* its parents that are disclosable values themselves.
     * - By default *all* disclosable claims are disclosed, therefore this method can only be used to *undo* any
     *   concealment operations previously performed by either {@link SdJwtPresentationBuilder.conceal} or {@link
     *   SdJwtPresentationBuilder.conceal_all}.
     */
    disclose(path: string): SdJwtPresentationBuilder;
    /**
     * Returns the resulting {@link SdJwt} together with all omitted disclosures.
     */
    finish(): SdJwtPresentationResult;
    constructor(sd_jwt: SdJwt, hasher: Hasher);
}

